import type { NordicPlatformType } from '../../common/types';
import type { DeviceOS } from './types';

import { getReq } from '@meli/server-context';

import { DC_COOKIE, LAST_COMMA_REGEX } from './utils/webview/constants';
import { setClientHints } from './utils/web/client-hints';
import { getDeviceInfo } from './utils/web/device-info';
import { getNetworkState } from './utils/web/network-state';
import { getProfileWithWebkitCookieInfo } from './utils/webview/cookie';
import { concatCookieValue, setCookie } from '../utils/webview/cookie';

const OS_INFO_REGEX = /osv?=[^,]+,?/g;

/**
 * Recollects device profile information from the request, cookies and HTTP headers.
 */
export function getDeviceProfile(platformType: NordicPlatformType) {
  if (platformType !== 'web') {
    return getProfileWithWebkitCookieInfo();
  }

  setClientHints();

  return {
    deviceInfo: getDeviceInfo(),
    networkState: getNetworkState(),
  };
}

export function setDeviceInfoCookie(deviceOS: DeviceOS) {
  const currentCookieValue = getReq().cookies[DC_COOKIE];
  const osCookiePart = concatCookieValue('os', deviceOS.name);
  const osvCookiePart = concatCookieValue('osv', deviceOS.version);
  const updatedCookieValue = currentCookieValue
    ? currentCookieValue.replace(OS_INFO_REGEX, (match) =>
        match.startsWith('os=') ? osCookiePart : osvCookiePart,
      )
    : osCookiePart + osvCookiePart;

  setCookie(DC_COOKIE, updatedCookieValue.replace(LAST_COMMA_REGEX, ''));
}
